import { serve } from 'https://deno.land/std@0.168.0/http/server.ts';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

interface ChatRequest {
    message: string;
    context?: 'campaigns' | 'creatives' | 'audits' | 'performance' | 'general';
}

interface ChatMessage {
    role: 'user' | 'assistant' | 'system';
    content: string;
}

serve(async (req) => {
    if (req.method === 'OPTIONS') {
        return new Response('ok', { headers: corsHeaders });
    }

    try {
        const supabaseUrl = Deno.env.get('SUPABASE_URL')!;
        const supabaseServiceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
        const openaiApiKey = Deno.env.get('OPENAI_API_KEY');
        const supabase = createClient(supabaseUrl, supabaseServiceKey);

        if (!openaiApiKey) {
            throw new Error('OpenAI API key not configured');
        }

        const authHeader = req.headers.get('Authorization');
        if (!authHeader) {
            throw new Error('Missing authorization header');
        }

        const { data: { user }, error: authError } = await supabase.auth.getUser(
            authHeader.replace('Bearer ', '')
        );
        if (authError || !user) {
            throw new Error('Unauthorized');
        }

        const { data: userData } = await supabase
            .from('users')
            .select('company_id')
            .eq('id', user.id)
            .single();

        if (!userData?.company_id) {
            throw new Error('User not associated with company');
        }

        const { message, context = 'general' } = await req.json() as ChatRequest;

        if (!message) {
            throw new Error('Missing message');
        }

        // Gather context data based on request
        let contextData = '';

        if (context === 'campaigns' || context === 'general') {
            const { data: campaigns } = await supabase
                .from('campaigns')
                .select('name, status, objective, impressions, clicks, spend')
                .eq('company_id', userData.company_id)
                .order('spend', { ascending: false })
                .limit(10);

            if (campaigns?.length) {
                contextData += '\n\nCAMPANHAS ATIVAS:\n';
                campaigns.forEach((c, i) => {
                    const ctr = c.impressions > 0 ? ((c.clicks / c.impressions) * 100).toFixed(2) : '0';
                    contextData += `${i + 1}. ${c.name} (${c.status}) - Spend: R$${c.spend?.toFixed(2) || 0}, CTR: ${ctr}%\n`;
                });
            }
        }

        if (context === 'creatives' || context === 'general') {
            const { data: creatives } = await supabase
                .from('creatives')
                .select('name, type, status, impressions, clicks, ctr, cpc, performance_score')
                .eq('company_id', userData.company_id)
                .order('performance_score', { ascending: false })
                .limit(10);

            if (creatives?.length) {
                contextData += '\n\nCRIATIVOS TOP PERFORMANCE:\n';
                creatives.forEach((c, i) => {
                    contextData += `${i + 1}. ${c.name} (${c.type}) - CTR: ${c.ctr?.toFixed(2) || 0}%, CPC: R$${c.cpc?.toFixed(2) || 0}, Score: ${c.performance_score || 0}%\n`;
                });
            }
        }

        if (context === 'audits' || context === 'general') {
            const { data: audits } = await supabase
                .from('audits')
                .select('status, compliance_score, performance_score, created_at')
                .eq('company_id', userData.company_id)
                .order('created_at', { ascending: false })
                .limit(20);

            if (audits?.length) {
                const approved = audits.filter(a => a.status === 'approved').length;
                const rejected = audits.filter(a => a.status === 'rejected').length;
                const avgCompliance = audits.reduce((acc, a) => acc + (a.compliance_score || 0), 0) / audits.length;

                contextData += '\n\nRESUMO DE AUDITORIAS:\n';
                contextData += `Total: ${audits.length}, Aprovados: ${approved}, Rejeitados: ${rejected}\n`;
                contextData += `Média de Conformidade: ${avgCompliance.toFixed(1)}%\n`;
            }
        }

        if (context === 'performance' || context === 'general') {
            const { data: metrics } = await supabase
                .from('campaign_metrics')
                .select('impressions, clicks, spend, conversions')
                .eq('company_id', userData.company_id);

            if (metrics?.length) {
                const totals = metrics.reduce(
                    (acc, m) => ({
                        impressions: acc.impressions + (m.impressions || 0),
                        clicks: acc.clicks + (m.clicks || 0),
                        spend: acc.spend + (m.spend || 0),
                        conversions: acc.conversions + (m.conversions || 0),
                    }),
                    { impressions: 0, clicks: 0, spend: 0, conversions: 0 }
                );

                const ctr = totals.impressions > 0 ? (totals.clicks / totals.impressions * 100).toFixed(2) : '0';
                const cpc = totals.clicks > 0 ? (totals.spend / totals.clicks).toFixed(2) : '0';

                contextData += '\n\nMÉTRICAS GERAIS:\n';
                contextData += `Impressões: ${totals.impressions.toLocaleString()}\n`;
                contextData += `Cliques: ${totals.clicks.toLocaleString()}\n`;
                contextData += `CTR: ${ctr}%\n`;
                contextData += `CPC Médio: R$${cpc}\n`;
                contextData += `Spend Total: R$${totals.spend.toLocaleString()}\n`;
                contextData += `Conversões: ${totals.conversions}\n`;
            }
        }

        const systemPrompt = `Você é um assistente de IA especializado em análise de anúncios Meta Ads (Facebook/Instagram). 
Você ajuda gestores de tráfego a:
- Analisar performance de campanhas e criativos
- Identificar oportunidades de otimização
- Sugerir melhorias baseadas em dados
- Explicar métricas e tendências
- Recomendar ações para melhorar resultados

Responda sempre em português brasileiro, de forma clara e objetiva.
Use dados concretos quando disponíveis.
Seja proativo em sugerir ações práticas.

${contextData ? 'DADOS DA CONTA DO USUÁRIO:' + contextData : 'Sem dados de campanha disponíveis ainda.'}`;

        const messages: ChatMessage[] = [
            { role: 'system', content: systemPrompt },
            { role: 'user', content: message },
        ];

        const openaiResponse = await fetch('https://api.openai.com/v1/chat/completions', {
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${openaiApiKey}`,
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                model: 'gpt-4o-mini',
                messages,
                temperature: 0.7,
                max_tokens: 1000,
            }),
        });

        if (!openaiResponse.ok) {
            const errorData = await openaiResponse.json();
            console.error('OpenAI error:', errorData);
            throw new Error('Failed to get AI response');
        }

        const openaiData = await openaiResponse.json();
        const assistantMessage = openaiData.choices?.[0]?.message?.content;

        if (!assistantMessage) {
            throw new Error('Empty AI response');
        }

        // Log chat interaction
        await supabase.from('ai_chat_history').insert({
            company_id: userData.company_id,
            user_id: user.id,
            user_message: message,
            assistant_message: assistantMessage,
            context,
            tokens_used: openaiData.usage?.total_tokens || 0,
        });

        return new Response(
            JSON.stringify({
                success: true,
                message: assistantMessage,
                context,
                tokens_used: openaiData.usage?.total_tokens || 0,
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 200,
            }
        );

    } catch (error) {
        console.error('AI Chat error:', error);
        return new Response(
            JSON.stringify({
                success: false,
                error: String(error),
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 400,
            }
        );
    }
});

import { serve } from 'https://deno.land/std@0.168.0/http/server.ts';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

interface SuggestionRequest {
    creative_id?: string;
    campaign_id?: string;
}

serve(async (req) => {
    if (req.method === 'OPTIONS') {
        return new Response('ok', { headers: corsHeaders });
    }

    try {
        const supabaseUrl = Deno.env.get('SUPABASE_URL')!;
        const supabaseServiceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
        const openaiApiKey = Deno.env.get('OPENAI_API_KEY');
        const supabase = createClient(supabaseUrl, supabaseServiceKey);

        if (!openaiApiKey) {
            throw new Error('OpenAI API key not configured');
        }

        const authHeader = req.headers.get('Authorization');
        if (!authHeader) {
            throw new Error('Missing authorization header');
        }

        const { data: { user }, error: authError } = await supabase.auth.getUser(
            authHeader.replace('Bearer ', '')
        );
        if (authError || !user) {
            throw new Error('Unauthorized');
        }

        const { data: userData } = await supabase
            .from('users')
            .select('company_id')
            .eq('id', user.id)
            .single();

        if (!userData?.company_id) {
            throw new Error('User not associated with company');
        }

        const { creative_id, campaign_id } = await req.json() as SuggestionRequest;

        // Get context data
        let creativeContext = '';
        let campaignContext = '';

        if (creative_id) {
            const { data: creative } = await supabase
                .from('creatives')
                .select('*')
                .eq('id', creative_id)
                .single();

            if (creative) {
                creativeContext = `
CRIATIVO ATUAL:
Nome: ${creative.name}
Tipo: ${creative.type}
Headline: ${creative.headline || 'N/A'}
Texto: ${creative.text || 'N/A'}
CTA: ${creative.call_to_action || 'N/A'}
CTR: ${creative.ctr?.toFixed(2) || 0}%
CPC: R$${creative.cpc?.toFixed(2) || 0}
Score: ${creative.performance_score || 0}%
`;
            }
        }

        // Get top performing creatives for reference
        const { data: topCreatives } = await supabase
            .from('creatives')
            .select('name, type, headline, text, call_to_action, ctr, cpc, performance_score')
            .eq('company_id', userData.company_id)
            .order('performance_score', { ascending: false })
            .limit(5);

        if (topCreatives?.length) {
            campaignContext = '\nTOP 5 CRIATIVOS DE MELHOR PERFORMANCE:\n';
            topCreatives.forEach((c, i) => {
                campaignContext += `${i + 1}. ${c.name} (CTR: ${c.ctr?.toFixed(2) || 0}%, Score: ${c.performance_score || 0}%)\n`;
                if (c.headline) campaignContext += `   Headline: ${c.headline}\n`;
                if (c.text) campaignContext += `   Texto: ${c.text.substring(0, 100)}...\n`;
            });
        }

        // Get campaign info if provided
        if (campaign_id) {
            const { data: campaign } = await supabase
                .from('campaigns')
                .select('name, objective, status')
                .eq('id', campaign_id)
                .single();

            if (campaign) {
                campaignContext += `\nCAMPANHA: ${campaign.name}\nOBJETIVO: ${campaign.objective || 'N/A'}\n`;
            }
        }

        const systemPrompt = `Você é um especialista em criação de anúncios para Meta Ads (Facebook/Instagram).
Baseado nos dados dos criativos, gere sugestões práticas e específicas para melhorar a performance.

Responda em JSON com a seguinte estrutura:
{
  "headline_suggestions": ["sugestão 1", "sugestão 2", "sugestão 3"],
  "body_text_suggestions": ["sugestão 1", "sugestão 2"],
  "cta_suggestions": ["CTA 1", "CTA 2"],
  "visual_recommendations": ["recomendação 1", "recomendação 2"],
  "a_b_test_ideas": ["ideia de teste 1", "ideia de teste 2"],
  "optimization_tips": ["dica 1", "dica 2", "dica 3"]
}

Seja específico e prático. Use insights dos melhores criativos como inspiração.`;

        const userPrompt = `Gere sugestões de novos criativos e otimizações baseado nestes dados:
${creativeContext}
${campaignContext}

Foque em:
1. Headlines que chamem atenção
2. Textos persuasivos e diretos
3. CTAs efetivos
4. Elementos visuais que convertem
5. Ideias para testes A/B`;

        const openaiResponse = await fetch('https://api.openai.com/v1/chat/completions', {
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${openaiApiKey}`,
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                model: 'gpt-4o-mini',
                messages: [
                    { role: 'system', content: systemPrompt },
                    { role: 'user', content: userPrompt },
                ],
                temperature: 0.8,
                max_tokens: 1500,
            }),
        });

        if (!openaiResponse.ok) {
            throw new Error('Failed to get AI suggestions');
        }

        const openaiData = await openaiResponse.json();
        const content = openaiData.choices?.[0]?.message?.content;

        let suggestions;
        try {
            suggestions = JSON.parse(content);
        } catch {
            // If not valid JSON, return raw content
            suggestions = { raw_suggestions: content };
        }

        // Save suggestions to database
        await supabase.from('ai_suggestions').insert({
            company_id: userData.company_id,
            creative_id: creative_id || null,
            campaign_id: campaign_id || null,
            suggestions,
            tokens_used: openaiData.usage?.total_tokens || 0,
        });

        return new Response(
            JSON.stringify({
                success: true,
                suggestions,
                tokens_used: openaiData.usage?.total_tokens || 0,
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 200,
            }
        );

    } catch (error) {
        console.error('AI suggestions error:', error);
        return new Response(
            JSON.stringify({
                success: false,
                error: String(error),
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 400,
            }
        );
    }
});
